function getHeatmapColor(value) {
    // Gradient from dark blue (low) to cyan (medium) to yellow/orange (high)
    if (value < 0.3) {
        return `rgba(30, 64, 175, ${0.3 + value})`;
    } else if (value < 0.6) {
        return `rgba(6, 182, 212, ${0.4 + value * 0.5})`;
    } else {
        return `rgba(245, 158, 11, ${0.5 + value * 0.4})`;
    }
}
